const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

const premiumForItem = (item: { type: string }): number => {
  const base = BASE_PREMIUMS[item.type];
  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  const itemsTotal = items.reduce(
    (sum: number, item: any) => sum + premiumForItem(item),
    0,
  );
  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
  return { results: [{ premium }] };
};

